/** True when grid cell (ix, iy) is land. */
export function worldLand(ix: number, iy: number): boolean {
  return ROWS_DATA[iy]?.charCodeAt(ix) === 49
}

/** Grid cell (fractional) for a lat/lon — for pinning city nodes. */
export function worldCell(lat: number, lon: number): { x: number; y: number } {
  return {
    x: ((lon + 180) / 360) * 256,
    y: ((85 - lat) / (85 - (-60))) * 112,
  }
}
